"use client";

/**
 * Search results page — cold build on @gunjo/ui@0.0.1-alpha.2.
 *
 * Discovery notes (docs-first, gunjo.jp; source consulted where docs were thin):
 *  - SearchInput: controlled via `value`/`onValueChange`. No `loading` / result-count
 *    props — those are the app's job. Clear button is tabIndex=-1 (mouse-only).
 *  - Combobox: `options: {value,label,disabled?}[]`, controlled `value`/`onValueChange`
 *    ("" on clear). Proper role="combobox" + listbox semantics via Command/Popover.
 *  - Select: thin native <select> wrapper. Standard value/onChange + <option> children.
 *  - Checkbox: role="checkbox" + aria-checked; `checked`/`onCheckedChange`.
 *  - Badge: <div>, 4 variants, NO dismiss button — compose Badge + Button for chips.
 *  - TagEditor: `value: string[]` + `onValueChange`. Used here as a tag *filter* editor.
 *  - Pagination: PRESENTATIONAL compound parts only (nav/ul/li + <a> links). No page
 *    math, no onPageChange — the app owns the window. isActive => aria-current="page".
 *    Links have no href, so we render them as buttons via `asChild`-less... see note below.
 *  - EmptyState: { icon, title, description, action }.
 *  - Skeleton: shape="rectangle"|"circle"|"text".
 */

import * as React from "react";
import {
  IconSearch,
  IconAdjustmentsHorizontal,
  IconVideo,
  IconFileText,
  IconArticle,
  IconClock,
  IconUser,
  IconX,
} from "@tabler/icons-react";
import {
  SearchInput,
  Combobox,
  Select,
  Checkbox,
  Badge,
  TagEditor,
  EmptyState,
  Skeleton,
  Button,
  Label,
  Card,
  CardHeader,
  CardTitle,
  CardDescription,
  CardContent,
  CardFooter,
  Separator,
  Pagination,
  PaginationContent,
  PaginationItem,
  PaginationLink,
  PaginationPrevious,
  PaginationNext,
  PaginationEllipsis,
} from "@gunjo/ui";
import {
  ARTICLES,
  CATEGORIES,
  TYPES,
  SORTS,
  ALL_TAGS,
  type Article,
  type SortValue,
} from "./data";

const PAGE_SIZE = 8;

const typeIcon: Record<Article["type"], React.ReactNode> = {
  article: <IconArticle className="h-3.5 w-3.5" aria-hidden="true" />,
  video: <IconVideo className="h-3.5 w-3.5" aria-hidden="true" />,
  doc: <IconFileText className="h-3.5 w-3.5" aria-hidden="true" />,
};

function formatDate(iso: string): string {
  return new Date(iso).toLocaleDateString("ja-JP", {
    year: "numeric",
    month: "long",
    day: "numeric",
  });
}

/** Build the visible page window with ellipsis. Pagination ships no math, so this is ours. */
function pageWindow(current: number, total: number): (number | "…")[] {
  if (total <= 7) return Array.from({ length: total }, (_, i) => i + 1);
  const out: (number | "…")[] = [1];
  const start = Math.max(2, current - 1);
  const end = Math.min(total - 1, current + 1);
  if (start > 2) out.push("…");
  for (let p = start; p <= end; p++) out.push(p);
  if (end < total - 1) out.push("…");
  out.push(total);
  return out;
}

export default function SearchPage() {
  // --- search + filter state ---
  const [query, setQuery] = React.useState("");
  const [selectedCategories, setSelectedCategories] = React.useState<Set<string>>(new Set());
  const [type, setType] = React.useState<string>(""); // combobox value ("" = any)
  const [tagFilters, setTagFilters] = React.useState<string[]>([]);
  const [sort, setSort] = React.useState<SortValue>("relevance");
  const [page, setPage] = React.useState(1);

  // --- loading flow: simulate a fetch whenever inputs change ---
  const [loading, setLoading] = React.useState(true);
  React.useEffect(() => {
    setLoading(true);
    const t = setTimeout(() => setLoading(false), 450);
    return () => clearTimeout(t);
  }, [query, selectedCategories, type, tagFilters, sort]);

  // Reset to page 1 when the result set changes.
  React.useEffect(() => {
    setPage(1);
  }, [query, selectedCategories, type, tagFilters, sort]);

  // --- derive results ---
  const filtered = React.useMemo(() => {
    const q = query.trim().toLowerCase();
    let rows = ARTICLES.filter((a) => {
      if (q) {
        const hay = `${a.title} ${a.snippet} ${a.tags.join(" ")} ${a.author}`.toLowerCase();
        if (!hay.includes(q)) return false;
      }
      if (selectedCategories.size > 0 && !selectedCategories.has(a.category)) return false;
      if (type && a.type !== type) return false;
      if (tagFilters.length > 0 && !tagFilters.every((t) => a.tags.includes(t))) return false;
      return true;
    });

    rows = [...rows].sort((x, y) => {
      switch (sort) {
        case "newest":
          return y.publishedAt.localeCompare(x.publishedAt);
        case "oldest":
          return x.publishedAt.localeCompare(y.publishedAt);
        case "shortest":
          return x.readingMinutes - y.readingMinutes;
        case "relevance":
        default:
          return y.popularity - x.popularity;
      }
    });
    return rows;
  }, [query, selectedCategories, type, tagFilters, sort]);

  const totalPages = Math.max(1, Math.ceil(filtered.length / PAGE_SIZE));
  const safePage = Math.min(page, totalPages);
  const pageRows = filtered.slice((safePage - 1) * PAGE_SIZE, safePage * PAGE_SIZE);

  // --- active filter chips (each removable) + clear all ---
  const activeChips: { key: string; label: string; clear: () => void }[] = [];
  if (query.trim()) {
    activeChips.push({ key: "q", label: `“${query.trim()}”`, clear: () => setQuery("") });
  }
  selectedCategories.forEach((c) => {
    activeChips.push({
      key: `cat:${c}`,
      label: c,
      clear: () =>
        setSelectedCategories((prev) => {
          const next = new Set(prev);
          next.delete(c);
          return next;
        }),
    });
  });
  if (type) {
    const t = TYPES.find((x) => x.value === type);
    activeChips.push({ key: `type:${type}`, label: t?.label ?? type, clear: () => setType("") });
  }
  tagFilters.forEach((t) => {
    activeChips.push({
      key: `tag:${t}`,
      label: `#${t}`,
      clear: () => setTagFilters((prev) => prev.filter((x) => x !== t)),
    });
  });

  function clearAll() {
    setQuery("");
    setSelectedCategories(new Set());
    setType("");
    setTagFilters([]);
  }

  function toggleCategory(cat: string) {
    setSelectedCategories((prev) => {
      const next = new Set(prev);
      if (next.has(cat)) next.delete(cat);
      else next.add(cat);
      return next;
    });
  }

  const goToPage = (p: number) => {
    if (p >= 1 && p <= totalPages) setPage(p);
  };

  const resultLabel = loading
    ? "検索中…"
    : `${
        query.trim() ? `「${query.trim()}」の検索結果：` : ""
      }${filtered.length.toLocaleString()}件`;

  return (
    <main className="mx-auto w-full max-w-6xl px-4 py-8 sm:px-6 lg:px-8">
      {/* Header / search bar */}
      <header className="mb-6">
        <h1 className="mb-1 text-2xl font-semibold tracking-tight text-foreground">
          ライブラリを検索
        </h1>
        <p className="mb-4 text-sm text-muted-foreground">
          プラットフォーム開発のためのガイド、チュートリアル、リファレンス。
        </p>
        <div className="flex flex-col gap-3 sm:flex-row sm:items-center">
          <div className="flex-1">
            <label htmlFor="library-search" className="sr-only">
              記事を検索
            </label>
            <SearchInput
              id="library-search"
              value={query}
              onValueChange={setQuery}
              placeholder="記事・タグ・著者を検索…"
              clearLabel="検索をクリア"
            />
          </div>
          <div className="flex items-center gap-2 sm:w-56">
            <Label htmlFor="sort-select" className="shrink-0 text-muted-foreground">
              並び替え
            </Label>
            <Select
              id="sort-select"
              value={sort}
              onChange={(e) => setSort(e.target.value as SortValue)}
              aria-label="検索結果を並び替え"
            >
              {SORTS.map((s) => (
                <option key={s.value} value={s.value}>
                  {s.label}
                </option>
              ))}
            </Select>
          </div>
        </div>
        <p
          className="mt-3 text-sm font-medium text-foreground"
          role="status"
          aria-live="polite"
        >
          {resultLabel}
        </p>
      </header>

      <div className="flex flex-col gap-6 lg:flex-row">
        {/* Filter sidebar */}
        <aside className="w-full shrink-0 lg:w-64" aria-label="絞り込み">
          <div className="rounded-lg border border-border bg-card p-4">
            <div className="mb-3 flex items-center gap-2 text-sm font-semibold text-foreground">
              <IconAdjustmentsHorizontal className="h-4 w-4" aria-hidden="true" />
              絞り込み
            </div>

            {/* Category checkboxes */}
            <fieldset className="mb-4">
              <legend className="mb-2 text-xs font-semibold uppercase tracking-wide text-muted-foreground">
                カテゴリー
              </legend>
              <div className="space-y-2">
                {CATEGORIES.map((cat) => {
                  const id = `cat-${cat}`;
                  const checked = selectedCategories.has(cat);
                  const count = ARTICLES.filter((a) => a.category === cat).length;
                  return (
                    <div key={cat} className="flex items-center gap-2">
                      <Checkbox
                        id={id}
                        checked={checked}
                        onCheckedChange={() => toggleCategory(cat)}
                      />
                      <label
                        htmlFor={id}
                        className="flex flex-1 cursor-pointer items-center justify-between text-sm text-foreground"
                      >
                        <span>{cat}</span>
                        <span className="text-xs text-muted-foreground">{count}</span>
                      </label>
                    </div>
                  );
                })}
              </div>
            </fieldset>

            <Separator className="my-4" />

            {/* Type combobox */}
            <div className="mb-4">
              <Label htmlFor="type-combobox" className="mb-2 block text-xs font-semibold uppercase tracking-wide text-muted-foreground">
                種類
              </Label>
              <Combobox
                id="type-combobox"
                options={TYPES}
                value={type}
                onValueChange={setType}
                placeholder="すべての種類"
                searchPlaceholder="種類を絞り込む…"
                emptyMessage="該当する種類がありません。"
              />
            </div>

            <Separator className="my-4" />

            {/* Tag filter via TagEditor — it ships its own "Tags" label, so we don't add one. */}
            <div>
              <TagEditor
                label={
                  <span className="text-xs font-semibold uppercase tracking-wide text-muted-foreground">
                    タグ
                  </span>
                }
                value={tagFilters}
                onValueChange={setTagFilters}
                suggestions={ALL_TAGS}
                placeholder="タグで絞り込む…"
              />
            </div>
          </div>
        </aside>

        {/* Results column */}
        <section className="min-w-0 flex-1" aria-label="検索結果">
          {/* Active filter chips */}
          {activeChips.length > 0 && (
            <div className="mb-4 flex flex-wrap items-center gap-2">
              {activeChips.map((chip) => (
                <span key={chip.key} className="inline-flex items-center">
                  <Badge variant="secondary" className="gap-1 pr-1">
                    <span>{chip.label}</span>
                    <button
                      type="button"
                      onClick={chip.clear}
                      aria-label={`絞り込み ${chip.label} を解除`}
                      className="ml-0.5 inline-flex h-4 w-4 items-center justify-center rounded-full text-muted-foreground hover:bg-foreground/10 hover:text-foreground focus-visible:outline-none focus-visible:ring-1 focus-visible:ring-ring"
                    >
                      <IconX className="h-3 w-3" aria-hidden="true" />
                    </button>
                  </Badge>
                </span>
              ))}
              <Button variant="ghost" size="sm" onClick={clearAll}>
                すべて解除
              </Button>
            </div>
          )}

          {/* Loading skeletons */}
          {loading ? (
            <ul className="space-y-3" aria-hidden="true">
              {Array.from({ length: 4 }).map((_, i) => (
                <li key={i}>
                  <Card>
                    <CardHeader>
                      <Skeleton shape="text" className="w-1/3" />
                      <Skeleton className="h-5 w-2/3" />
                    </CardHeader>
                    <CardContent className="space-y-2">
                      <Skeleton shape="text" />
                      <Skeleton shape="text" className="w-4/5" />
                    </CardContent>
                  </Card>
                </li>
              ))}
            </ul>
          ) : pageRows.length === 0 ? (
            // Empty state
            <EmptyState
              icon={<IconSearch className="h-6 w-6" />}
              title="結果が見つかりません"
              description={
                query.trim() || activeChips.length > 0
                  ? "絞り込みを解除するか、もう少し広い条件で検索してみてください。"
                  : "まだここには何もありません。"
              }
              action={
                activeChips.length > 0 ? (
                  <Button variant="outline" size="sm" onClick={clearAll}>
                    絞り込みをすべて解除
                  </Button>
                ) : undefined
              }
            />
          ) : (
            <>
              <ul className="space-y-3">
                {pageRows.map((a) => (
                  <li key={a.id}>
                    <Card className="transition-colors hover:border-foreground/20">
                      <CardHeader>
                        <div className="flex flex-wrap items-center gap-2">
                          <Badge variant="outline" className="gap-1">
                            {typeIcon[a.type]}
                            {TYPES.find((t) => t.value === a.type)?.label ?? a.type}
                          </Badge>
                          <Badge variant="secondary">{a.category}</Badge>
                        </div>
                        <CardTitle className="text-base">
                          <a
                            href="#"
                            className="rounded-sm hover:underline focus-visible:outline-none focus-visible:ring-1 focus-visible:ring-ring"
                          >
                            {a.title}
                          </a>
                        </CardTitle>
                        <CardDescription>{a.snippet}</CardDescription>
                      </CardHeader>
                      <CardFooter className="flex flex-wrap items-center gap-x-4 gap-y-2 text-xs text-muted-foreground">
                        <span className="inline-flex items-center gap-1">
                          <IconUser className="h-3.5 w-3.5" aria-hidden="true" />
                          {a.author}
                        </span>
                        <span className="inline-flex items-center gap-1">
                          <IconClock className="h-3.5 w-3.5" aria-hidden="true" />
                          約{a.readingMinutes}分
                        </span>
                        <span>{formatDate(a.publishedAt)}</span>
                        <span className="flex flex-wrap gap-1">
                          {a.tags.map((t) => (
                            <button
                              key={t}
                              type="button"
                              onClick={() =>
                                setTagFilters((prev) =>
                                  prev.includes(t) ? prev : [...prev, t],
                                )
                              }
                              className="rounded-full bg-muted px-2 py-0.5 text-[11px] text-muted-foreground hover:bg-foreground/10 hover:text-foreground focus-visible:outline-none focus-visible:ring-1 focus-visible:ring-ring"
                            >
                              #{t}
                            </button>
                          ))}
                        </span>
                      </CardFooter>
                    </Card>
                  </li>
                ))}
              </ul>

              {/* Pagination */}
              {totalPages > 1 && (
                <div className="mt-6">
                  <Pagination>
                    <PaginationContent>
                      <PaginationItem>
                        <PaginationPrevious
                          role="button"
                          tabIndex={safePage === 1 ? -1 : 0}
                          aria-disabled={safePage === 1}
                          onClick={() => goToPage(safePage - 1)}
                          onKeyDown={(e) => {
                            if (e.key === "Enter" || e.key === " ") {
                              e.preventDefault();
                              goToPage(safePage - 1);
                            }
                          }}
                          className="cursor-pointer"
                        />
                      </PaginationItem>

                      {pageWindow(safePage, totalPages).map((p, i) =>
                        p === "…" ? (
                          <PaginationItem key={`e${i}`}>
                            <PaginationEllipsis />
                          </PaginationItem>
                        ) : (
                          <PaginationItem key={p}>
                            <PaginationLink
                              role="button"
                              tabIndex={0}
                              isActive={p === safePage}
                              aria-label={`${p}ページ目へ`}
                              onClick={() => goToPage(p)}
                              onKeyDown={(e) => {
                                if (e.key === "Enter" || e.key === " ") {
                                  e.preventDefault();
                                  goToPage(p);
                                }
                              }}
                              className="cursor-pointer"
                            >
                              {p}
                            </PaginationLink>
                          </PaginationItem>
                        ),
                      )}

                      <PaginationItem>
                        <PaginationNext
                          role="button"
                          tabIndex={safePage === totalPages ? -1 : 0}
                          aria-disabled={safePage === totalPages}
                          onClick={() => goToPage(safePage + 1)}
                          onKeyDown={(e) => {
                            if (e.key === "Enter" || e.key === " ") {
                              e.preventDefault();
                              goToPage(safePage + 1);
                            }
                          }}
                          className="cursor-pointer"
                        />
                      </PaginationItem>
                    </PaginationContent>
                  </Pagination>
                  <p className="mt-2 text-center text-xs text-muted-foreground">
                    {totalPages}ページ中 {safePage}ページ目
                  </p>
                </div>
              )}
            </>
          )}
        </section>
      </div>
    </main>
  );
}
